import React, { useState, useEffect } from 'react';
import './ClosedTradesModal.css';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  CircularProgress,
  Alert,
  IconButton,
  useTheme,
  useMediaQuery,
  Tooltip
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh,
  Info
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const ClosedTradesModal = ({ open, onClose }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [trades, setTrades] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [stats, setStats] = useState({
    totalTrades: 0,
    winningTrades: 0,
    losingTrades: 0,
    totalPnL: 0,
    winRate: 0
  });

  const loadTrades = async () => {
    try {
      setLoading(true);
      setError('');
      
      const response = await dashboardService.getClosedTrades();
      
      if (response?.data && Array.isArray(response.data)) {
        setTrades(response.data);
        calculateStats(response.data);
      }
    } catch (error) {
      console.error('Erro ao carregar trades:', error);
      setError('Erro ao carregar histórico de operações');
    } finally {
      setLoading(false);
    }
  };

  const calculateStats = (tradesData) => {
    const stats = tradesData.reduce((acc, trade) => {
      acc.totalTrades++;
      acc.totalPnL += parseFloat(trade.pnl || 0);
      
      if (parseFloat(trade.roe) > 0) {
        acc.winningTrades++;
      } else if (parseFloat(trade.roe) < 0) {
        acc.losingTrades++;
      }
      
      return acc;
    }, {
      totalTrades: 0,
      winningTrades: 0,
      losingTrades: 0,
      totalPnL: 0
    });
    
    stats.winRate = stats.totalTrades > 0 
      ? (stats.winningTrades / stats.totalTrades) * 100 
      : 0;
    
    setStats(stats);
  };

  useEffect(() => {
    if (open) {
      loadTrades();
    }
  }, [open]);

  const formatCurrency = (value) => {
    if (!value) return '$0.00';
    const numValue = parseFloat(value);
    return `$${numValue.toFixed(4)}`;
  };

  const formatPercentage = (value) => {
    if (!value) return '0.00%';
    const numValue = parseFloat(value);
    return `${numValue >= 0 ? '+' : ''}${numValue.toFixed(2)}%`;
  };

  const formatDateTime = (dateString) => {
    if (!dateString) return '-';
    return new Date(dateString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: '2-digit',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getSideColor = (side) => {
    return side === 'buy' || side === 'long' ? theme.palette.success.main : theme.palette.error.main;
  };

  const getSideIcon = (side) => {
    return side === 'buy' || side === 'long' ? <TrendingUp /> : <TrendingDown />;
  };

  return (
    <Dialog 
      open={open} 
      onClose={onClose} 
      maxWidth="lg" 
      fullWidth
      fullScreen={isMobile}
      className="closed-trades-modal"
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        borderBottom: `1px solid ${theme.palette.divider}`
      }}>
        <Typography variant="h6" component="div">
          Operações Encerradas
        </Typography>
        <Box sx={{ display: 'flex', gap: 1 }}>
          <IconButton onClick={loadTrades} disabled={loading} size="small">
            <Refresh />
          </IconButton>
          <IconButton onClick={onClose} size="small">
            <Close />
          </IconButton>
        </Box>
      </DialogTitle>
      
      <DialogContent sx={{ p: 2 }}>
        {/* Estatísticas */}
        <Box className="stats-container">
          <Box className="stat-item">
            <Typography className="stat-label">Total de Trades</Typography>
            <Typography className="stat-value">{stats.totalTrades}</Typography>
          </Box>
          <Box className="stat-item">
            <Typography className="stat-label">Win Rate</Typography>
            <Typography 
              className={`stat-value ${stats.winRate >= 50 ? 'stat-value-positive' : 'stat-value-negative'}`}
            >
              {stats.winRate.toFixed(2)}%
            </Typography>
          </Box>
          <Box className="stat-item">
            <Typography className="stat-label">PnL Total</Typography>
            <Typography 
              className={`stat-value ${stats.totalPnL >= 0 ? 'stat-value-positive' : 'stat-value-negative'}`}
            >
              {formatCurrency(stats.totalPnL)}
            </Typography>
          </Box>
          <Box className="stat-item">
            <Typography className="stat-label">Trades Ganhos</Typography>
            <Typography className="stat-value stat-value-positive">
              {stats.winningTrades}
            </Typography>
          </Box>
          <Box className="stat-item">
            <Typography className="stat-label">Trades Perdidos</Typography>
            <Typography className="stat-value stat-value-negative">
              {stats.losingTrades}
            </Typography>
          </Box>
        </Box>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}
        
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
            <CircularProgress />
          </Box>
        ) : trades.length === 0 ? (
          <Box className="empty-state">
            <Typography className="empty-state-title" variant="h6">
              Nenhuma operação encerrada encontrada
            </Typography>
            <Typography className="empty-state-description">
              As operações encerradas aparecerão aqui após serem sincronizadas
            </Typography>
          </Box>
        ) : (
          <TableContainer component={Paper} className="table-container">
            <Table stickyHeader>
              <TableHead>
                <TableRow className="table-header">
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Par</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Lado</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Tamanho</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Alavancagem</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Entrada</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Saída</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>PnL</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>ROE %</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                  <TableCell>
                    <Box sx={{ display: 'flex', alignItems: 'center' }}>
                      <strong>Fechado em</strong>
                      <Info className="info-icon" />
                    </Box>
                  </TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {trades.map((trade, index) => (
                  <TableRow key={trade.id || index} hover>
                    <TableCell>
                      <Typography variant="body2" fontWeight="bold">
                        {trade.symbol}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Chip
                        icon={getSideIcon(trade.side)}
                        label={trade.side === 'buy' || trade.side === 'long' ? 'LONG' : 'SHORT'}
                        size="small"
                        className={`side-chip ${trade.side === 'buy' || trade.side === 'long' ? 'long' : 'short'}`}
                      />
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {trade.size && trade.size !== '0' ? parseFloat(trade.size).toFixed(4) : '-'}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {trade.leverage}x
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {formatCurrency(trade.entry_price)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {formatCurrency(trade.exit_price)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography 
                        variant="body2" 
                        className={parseFloat(trade.pnl) >= 0 ? 'stat-value-positive' : 'stat-value-negative'}
                        fontWeight="bold"
                      >
                        {formatCurrency(trade.pnl)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography 
                        variant="body2"
                        className={parseFloat(trade.roe) >= 0 ? 'stat-value-positive' : 'stat-value-negative'}
                        fontWeight="bold"
                      >
                        {formatPercentage(trade.roe)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {formatDateTime(trade.close_time)}
                      </Typography>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default ClosedTradesModal;
